const base = { location:'Mount Lavinia', mode:'Online Only', duration:'06 - 08 months', awardingBody:'Qualifi, OTHM, UKEE, Nqual', credits:'120 Credits',
  accreditations:['Regulated by Ofqual','Approved by WES','Member of IAU'],
  entryRequirements:['Demonstrated ability and possess qualifications at the previous level','Spent time in an organisational role and shown capability','Seeking further professional development'],
  learningOutcomes:['Understand and apply principles in a professional environment','Improve employability through theory and practice','Analyse problem solving techniques','Work independently and as part of a team','Manage personal development and growth'],
  registrationDocs:['Passport Size Photo','Birth Certificate & NIC','CV','Education Documents (OL, AL, Other)','Service Letter']
};
function c(id,title,slug,level,faculty,extra={}) {
  let finalLevel = level;
  if (title.includes('Award') || title.includes('Certificate')) finalLevel = 'Short Courses';
  else if (title.includes('Level 7') || title.includes('Level 8')) finalLevel = 'Postgraduate';
  else if (title.includes('Level 4') || title.includes('Level 5') || title.includes('Level 6')) finalLevel = 'Undergraduate';
  else if (title.includes('Level 2') || title.includes('Level 3')) finalLevel = 'Diploma';
  
  const getDeptImage = (id) => {
    if (id >= 1 && id <= 15 && id !== 11) return '/images/courses/it.png';
    if (id >= 16 && id <= 19) return '/images/courses/data-science.png';
    if (id === 11 || (id >= 20 && id <= 25)) return '/images/courses/cyber-security.png';
    if (id >= 26 && id <= 46) return '/images/courses/business.png';
    if (id >= 47 && id <= 53) return '/images/courses/finance.png';
    if (id === 54) return '/images/courses/marketing.png';
    if (id === 55 || id === 56 || (id >= 57 && id <= 61)) return '/images/courses/business.png';
    if (id >= 62 && id <= 72) return '/images/hero-campus.png';
    return '/images/about-hero.png';
  };

  return {
    id, title, slug, level:finalLevel, faculty, 
    image: extra.image || getDeptImage(id),
    featured:!!extra.featured,
    description:extra.desc||`This program provides a comprehensive pathway for learners seeking to develop knowledge and skills in ${faculty.toLowerCase()}. The qualification is designed to equip students with industry-relevant competencies.`,
    location:extra.location||base.location,
    mode:extra.mode||base.mode,
    duration:extra.duration||base.duration,
    awardingBody:extra.ab||base.awardingBody,
    credits:extra.credits||base.credits,
    accreditations:base.accreditations,
    units:extra.units||null,
    entryRequirements:extra.entry||base.entryRequirements,
    learningOutcomes:extra.outcomes||base.learningOutcomes,
    registrationDocs:base.registrationDocs
  };
}

